<template>
	<view class="container">
		<view class="header">
			<text class="title">质量管理</text>
		</view>
		
		<view class="quality-stats">
			<view class="stat-card">
				<text class="stat-title">合格率</text>
				<text class="stat-value">{{ passRate }}%</text>
				<view class="stat-trend">
					<text class="trend-text">+2.5% 较昨日</text>
					<text class="trend-icon">↑</text>
				</view>
			</view>
			
			<view class="stat-card">
				<text class="stat-title">今日检测</text>
				<text class="stat-value">{{ todayInspections }}</text>
				<text class="stat-unit">件</text>
			</view>
			
			<view class="stat-card">
				<text class="stat-title">不合格数</text>
				<text class="stat-value">{{ rejectCount }}</text>
				<text class="stat-unit">件</text>
			</view>
			
			<view class="stat-card">
				<text class="stat-title">待检测</text>
				<text class="stat-value">{{ pendingInspections }}</text>
				<text class="stat-unit">件</text>
			</view>
		</view>
		
		<view class="quality-chart">
			<view class="section-header">
				<text class="section-title">质量趋势</text>
			</view>
			<view class="chart-placeholder">
				<text class="chart-text">质量趋势图表</text>
			</view>
		</view>
		
		<view class="inspection-section">
			<view class="section-header">
				<text class="section-title">质检记录</text>
				<text class="more">查看全部</text>
			</view>
			
			<view class="inspection-list">
				<view class="inspection-item" v-for="(item, index) in inspectionRecords" :key="index">
					<view class="inspection-header">
						<text class="inspection-id">质检#{{ item.id }}</text>
						<text class="inspection-result" :class="item.result">{{ item.resultText }}</text>
					</view>
					
					<view class="inspection-content">
						<view class="content-row">
							<text class="label">产品名称：</text>
							<text class="value">{{ item.product }}</text>
						</view>
						
						<view class="content-row">
							<text class="label">检测数量：</text>
							<text class="value">{{ item.quantity }} 件</text>
						</view>
						
						<view class="content-row">
							<text class="label">检测时间：</text>
							<text class="value">{{ item.inspectionTime }}</text>
						</view>
						
						<view class="content-row" v-if="item.defects.length > 0">
							<text class="label">缺陷类型：</text>
							<view class="defect-tags">
								<text class="defect-tag" v-for="(defect, idx) in item.defects" :key="idx">{{ defect }}</text>
							</view>
						</view>
					</view>
				</view>
			</view>
		</view>
		
		<view class="quality-actions">
			<button class="action-btn" @click="newInspection">新建质检</button>
			<button class="action-btn secondary" @click="viewQualityReport">质量报告</button>
		</view>
	</view>
</template>

<script>
export default {
	data() {
		return {
			passRate: 98.5,
			todayInspections: 560,
			rejectCount: 8,
			pendingInspections: 32,
			inspectionRecords: [
				{
					id: 'Q001',
					product: '产品A',
					quantity: 100,
					result: 'pass',
					resultText: '合格',
					inspectionTime: '2026-01-11 14:30',
					defects: []
				},
				{
					id: 'Q002',
					product: '产品B',
					quantity: 80,
					result: 'pass',
					resultText: '合格',
					inspectionTime: '2026-01-11 13:15',
					defects: []
				},
				{
					id: 'Q003',
					product: '产品C',
					quantity: 120,
					result: 'fail',
					resultText: '不合格',
					inspectionTime: '2026-01-11 11:45',
					defects: ['表面划痕', '尺寸偏差']
				},
				{
					id: 'Q004',
					product: '产品A',
					quantity: 90,
					result: 'pass',
					resultText: '合格',
					inspectionTime: '2026-01-11 10:20',
					defects: []
				},
				{
					id: 'Q005',
					product: '产品D',
					quantity: 60,
					result: 'fail',
					resultText: '不合格',
					inspectionTime: '2026-01-11 09:30',
					defects: ['性能不达标']
				}
			]
		};
	},
	methods: {
		newInspection() {
			uni.showToast({
				title: '新建质检功能开发中',
				icon: 'none'
			});
		},
		viewQualityReport() {
			uni.showToast({
				title: '查看质量报告功能开发中',
				icon: 'none'
			});
		}
	}
};
</script>

<style scoped>
.container {
	padding: 20rpx;
	background-color: #f5f5f5;
	min-height: 100vh;
}

.header {
	padding: 20rpx;
	background-color: #fff;
	border-radius: 10rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.title {
	font-size: 36rpx;
	font-weight: bold;
	color: #333;
}

.quality-stats {
	display: flex;
	gap: 20rpx;
	margin-bottom: 20rpx;
}

.stat-card {
	flex: 1;
	background-color: #fff;
	border-radius: 10rpx;
	padding: 20rpx;
	text-align: center;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.stat-title {
	font-size: 24rpx;
	color: #666;
	margin-bottom: 10rpx;
}

.stat-value {
	font-size: 48rpx;
	font-weight: bold;
	color: #007aff;
	margin-bottom: 8rpx;
}

.stat-unit {
	font-size: 24rpx;
	color: #8e8e93;
	margin-left: 8rpx;
}

.stat-trend {
	display: flex;
	justify-content: center;
	align-items: center;
	gap: 5rpx;
	margin-top: 8rpx;
}

.trend-text {
	font-size: 20rpx;
	color: #4cd964;
}

.trend-icon {
	font-size: 20rpx;
	color: #4cd964;
	font-weight: bold;
}

.quality-chart {
	background-color: #fff;
	border-radius: 10rpx;
	padding: 20rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.section-header {
	display: flex;
	justify-content: space-between;
	align-items: center;
	margin-bottom: 20rpx;
}

.section-title {
	font-size: 32rpx;
	font-weight: bold;
	color: #333;
}

.more {
	font-size: 24rpx;
	color: #007aff;
	cursor: pointer;
}

.chart-placeholder {
	height: 200rpx;
	background-color: #f9f9f9;
	border-radius: 8rpx;
	display: flex;
	justify-content: center;
	align-items: center;
}

.chart-text {
	font-size: 24rpx;
	color: #8e8e93;
}

.inspection-section {
	background-color: #fff;
	border-radius: 10rpx;
	padding: 20rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.inspection-list {
	display: flex;
	flex-direction: column;
	gap: 15rpx;
}

.inspection-item {
	background-color: #f9f9f9;
	border-radius: 8rpx;
	padding: 15rpx;
}

.inspection-header {
	display: flex;
	justify-content: space-between;
	align-items: center;
	margin-bottom: 12rpx;
}

.inspection-id {
	font-size: 28rpx;
	font-weight: bold;
	color: #333;
}

.inspection-result {
	font-size: 24rpx;
	padding: 4rpx 12rpx;
	border-radius: 15rpx;
	font-weight: bold;
}

.inspection-result.pass {
	background-color: #e8f8f5;
	color: #4cd964;
}

.inspection-result.fail {
	background-color: #ffebee;
	color: #ff2d55;
}

.inspection-content {
	display: flex;
	flex-direction: column;
	gap: 10rpx;
}

.content-row {
	display: flex;
	align-items: center;
	flex-wrap: wrap;
}

.label {
	font-size: 24rpx;
	color: #666;
	width: 120rpx;
}

.value {
	font-size: 24rpx;
	color: #333;
	flex: 1;
}

.defect-tags {
	display: flex;
	gap: 8rpx;
	flex-wrap: wrap;
	flex: 1;
}

.defect-tag {
	font-size: 22rpx;
	padding: 4rpx 10rpx;
	background-color: #ffebee;
	color: #ff2d55;
	border-radius: 12rpx;
}

.quality-actions {
	display: flex;
	gap: 15rpx;
}

.action-btn {
	flex: 1;
	padding: 20rpx;
	background-color: #007aff;
	color: #fff;
	border: none;
	border-radius: 10rpx;
	font-size: 28rpx;
	font-weight: bold;
	cursor: pointer;
	transition: all 0.3s;
}

.action-btn.secondary {
	background-color: #fff;
	color: #007aff;
	border: 1rpx solid #007aff;
}

.action-btn:hover {
	opacity: 0.8;
}
</style>